interface Printable {
  toString(): string;
}

interface HasArea {
  area(): number;
}

function printArea(shape: HasArea & Printable): void {
  console.log(`${shape.toString()} has area ${shape.area().toFixed(2)}`);
}

// No explicit 'implements' needed — shape matches
const circle = {
  radius: 5,
  area()     { return Math.PI * this.radius ** 2; },
  toString() { return `Circle(r=${this.radius})`; },
};

const rectangle = {
  width: 4,
  height: 6,
  area()     { return this.width * this.height; },
  toString() { return `Rectangle(${this.width}×${this.height})`; },
};

printArea(circle);
printArea(rectangle);

