interface ValidationResult {
  isValid: boolean;
  errors: string[];
  sanitized?: string;
}

function validateEmail(input: string): ValidationResult {
  const errors: string[] = [];
  const trimmed = input.trim().toLowerCase();

  if (!trimmed.includes("@")) errors.push("Missing @ symbol");
  if (!trimmed.includes(".")) errors.push("Missing domain extension");
  if (trimmed.length < 5)    errors.push("Too short");

  return {
    isValid:   errors.length === 0,
    errors,
    sanitized: errors.length === 0 ? trimmed : undefined,
  };
}

const { isValid: v1, errors: e1, sanitized: s1 } = validateEmail(" Alice@Example.COM ");
const { isValid: v2, errors: e2 } = validateEmail("notanemail");

console.log(`Valid: ${v1}, sanitized: ${s1}`);
console.log(`Invalid: ${v2}, errors: ${e2.join(", ")}`);

const STATUS_CODES = Object.freeze({
  OK:                  200,
  CREATED:             201,
  NO_CONTENT:          204,
  BAD_REQUEST:         400,
  UNAUTHORIZED:        401,
  FORBIDDEN:           403,
  NOT_FOUND:           404,
  INTERNAL_ERROR:      500,
} as const);

// STATUS_CODES.OK = 999;  // ← Runtime error AND TypeScript error

type StatusCode = typeof STATUS_CODES[keyof typeof STATUS_CODES];

function getStatusMessage(code: StatusCode): string {
  const messages: Record<StatusCode, string> = {
    200: "OK", 201: "Created", 204: "No Content",
    400: "Bad Request", 401: "Unauthorized",
    403: "Forbidden", 404: "Not Found", 500: "Internal Server Error",
  };
  return messages[code];
}

console.log(getStatusMessage(200));
console.log(getStatusMessage(404));
console.log(getStatusMessage(500));

