interface SuccessResponse {
  success: true;
  data: unknown;
  count: number;
}

interface ErrorResponse {
  success: false;
  error: string;
  code: number;
}

type ApiResponse = SuccessResponse | ErrorResponse;

function isSuccess(r: ApiResponse): r is SuccessResponse {
  return r.success === true;
}

function handleResponse(response: ApiResponse): void {
  if (isSuccess(response)) {
    console.log(`Success: ${response.count} items returned`);
  } else {
    console.log(`Error ${response.code}: ${response.error}`);
  }
}

handleResponse({ success: true,  data: [],          count: 42 });
handleResponse({ success: false, error: "Not found", code: 404 });
handleResponse({ success: true,  data: { id: 1 },   count: 1  });

type Color = `#${string}` | "transparent";
type Theme = { [key: string]: Color | Theme };

// Without 'satisfies': colors would be typed as 'Color' (too wide)
// With 'satisfies': colors are typed as their literal values
const palette = {
  primary:   "#6366f1",
  secondary: "#10b981",
  danger:    "#ef4444",
  warning:   "#f59e0b",
  transparent: "transparent" as const,
} satisfies Record<string, Color>;

// TypeScript knows exact literal types
const primaryUpper = palette.primary.toUpperCase();
const secUpper = palette.secondary.toUpperCase();

console.log(`Primary:   ${primaryUpper}`);
console.log(`Secondary: ${secUpper}`);
console.log(`Danger:    ${palette.danger}`);
console.log(`Warning:   ${palette.warning}`);
